import NextAuth from "next-auth"
import Credentials from "next-auth/providers/credentials"
import { prisma } from "@/lib/prisma"
import bcrypt from "bcryptjs"

export const { handlers, auth, signIn, signOut } = NextAuth({
  providers: [
    Credentials({
      credentials: {
        email: { label: "Email", type: "email" },
        password: { label: "Password", type: "password" },
      },
      async authorize(credentials) {
        const user = await prisma.user.findUnique({
          where: { email: credentials.email as string },
        })
        if (!user || !user.hashedPassword) return null
        const isValid = await bcrypt.compare(credentials.password as string, user.hashedPassword)
        return isValid ? { id: user.id, email: user.email, organizationId: user.organizationId, role: user.role } : null
      },
    }),
  ],
  callbacks: {
    async jwt({ token, user }) {
      // RAISON: user shape declared in src/types/next-auth.d.ts — narrow to expected fields
      if (user && typeof user === 'object') {
        const u = user as { organizationId?: string | null; role?: string | null }
        if (u.organizationId) token.organizationId = u.organizationId
        if (u.role) token.role = u.role
      }
      return token
    },
    async session({ session, token }) {
      // RAISON: token (JWT) may contain organizationId/role claims
      if (session?.user && token && typeof token === 'object') {
        const t = token as { organizationId?: string | null; role?: string | null }
        session.user.organizationId = t.organizationId ?? null
        session.user.role = t.role ?? 'USER'
      }
      return session
    },
  },
  pages: { signIn: "/auth/signin" },
})

import NextAuth from "next-auth"
import Credentials from "next-auth/providers/credentials"
import { prisma } from "@/lib/prisma"
import bcrypt from "bcryptjs"

export const { handlers, auth, signIn, signOut } = NextAuth({
  providers: [
    Credentials({
      credentials: {
        email: { label: "Email", type: "email" },
        password: { label: "Password", type: "password" },
      },
      async authorize(credentials) {
        const user = await prisma.user.findUnique({
          where: { email: credentials.email as string },
        })
        if (!user || !user.hashedPassword) return null
        const isValid = await bcrypt.compare(credentials.password as string, user.hashedPassword)
        return isValid ? { id: user.id, email: user.email, organizationId: user.organizationId, role: user.role } : null
      },
    }),
  ],
  callbacks: {
    async jwt({ token, user }) {
      // Les types user.organizationId et user.role sont déclarés dans src/types/next-auth.d.ts
      if (user?.organizationId) token.organizationId = user.organizationId
      if (user?.role) token.role = user.role
      return token
    },
    async session({ session, token }) {
      // Les types token.organizationId et session.user.organizationId sont déclarés dans src/types/next-auth.d.ts
      if (session.user) {
        session.user.organizationId = token.organizationId ?? null
        session.user.role = (token.role as string) ?? 'USER'
      }
      return session
    },
  },
  pages: { signIn: "/auth/signin" },
})

"use client";

import { useState, useEffect } from "react";
import { Plus, Trash2, CreditCard, X, CheckCircle2, StickyNote, Save, Banknote, Landmark } from "lucide-react";
import { toast } from "sonner";
import type { CheckoutAppointment, Extra, AppointmentSummary } from "@/types/models";

// --- SOUS-COMPOSANTS DE STRUCTURE ---

interface PaymentMethodBtnProps {
    id: string
    label: string
    icon: React.ComponentType<{ size?: number }>
    active: boolean
    disabled: boolean
    onClick: (id: string) => void
}

const PaymentMethodBtn = ({ id, label, icon: Icon, active, disabled, onClick }: PaymentMethodBtnProps) => (
    <button
        disabled={disabled}
        onClick={() => onClick(id)}
        className={`flex flex-col items-center gap-2 p-3 rounded-2xl border transition-all ${
            active ? 'bg-indigo-600 border-indigo-600 text-white shadow-lg shadow-indigo-100' : 'bg-white border-gray-100 text-gray-400 hover:border-indigo-200'
        } ${disabled && !active ? 'opacity-20' : ''}`}
    >
        <Icon size={20} />
        <span className="text-[10px] font-bold uppercase">{label}</span>
    </button>
);

interface ExtraRowProps {
    extra: Extra
    index: number
    isPaid: boolean
    onUpdate: (index: number, field: keyof Extra, value: string | number) => void
    onRemove: (index: number) => void
}

const ExtraRow = ({ extra, index, isPaid, onUpdate, onRemove }: ExtraRowProps) => (
    <div className="flex gap-2 items-center group">
        <input
            type="text"
            disabled={isPaid}
            placeholder="Désignation"
            className="flex-1 p-2.5 bg-gray-50 border-none rounded-xl text-sm focus:ring-1 focus:ring-indigo-500/20 disabled:bg-transparent disabled:font-medium"
            value={extra.label}
            onChange={(e) => onUpdate(index, "label", e.target.value)}
        />
        <div className="relative">
            <input
                type="number"
                disabled={isPaid}
                className="w-20 p-2.5 bg-gray-50 border-none rounded-xl text-sm text-right pr-6 focus:ring-1 focus:ring-indigo-500/20 disabled:bg-transparent disabled:font-bold"
                value={extra.price || ""}
                onChange={(e) => onUpdate(index, "price", Number(e.target.value))}
            />
            <span className="absolute right-2 top-1/2 -translate-y-1/2 text-[10px] text-gray-400">€</span>
        </div>
        {!isPaid && (
            <button onClick={() => onRemove(index)} className="p-2 text-red-300 hover:text-red-500 rounded-xl transition-all">
                <Trash2 size={16} />
            </button>
        )}
    </div>
);

// --- COMPOSANT PRINCIPAL ---

interface CheckoutModalProps {
    appointment: (CheckoutAppointment | AppointmentSummary) | null
    onClose: () => void
    onRefresh: () => void
}

export default function CheckoutModal({ appointment, onClose, onRefresh }: CheckoutModalProps) {
    const [extras, setExtras] = useState<Extra[]>([]);
    const [note, setNote] = useState("");
    const [paymentMethod, setPaymentMethod] = useState("CB");
    const [loading, setLoading] = useState(false);

    useEffect(() => {
        if (!appointment) return

        // Narrowing: appointment may be CheckoutAppointment or AppointmentSummary
        let rawExtras: string | Extra[] | undefined
        if ('extras' in appointment) {
          rawExtras = appointment.extras ?? (appointment.extendedProps?.extras as any)
        } else {
          rawExtras = appointment.extendedProps ? (appointment.extendedProps['extras'] as any) : undefined
        }
        setExtras(typeof rawExtras === 'string' ? JSON.parse(rawExtras || "[]") : (rawExtras || []))

        const noteVal = ('note' in appointment ? appointment.note : undefined) ?? ('Note' in appointment ? (appointment as any).Note : undefined) ?? appointment.extendedProps?.note ?? ''
        setNote(noteVal)

        const pm = ('paymentMethod' in appointment ? (appointment as any).paymentMethod : undefined) ?? appointment.extendedProps?.paymentMethod ?? 'CB'
        setPaymentMethod(pm)
    }, [appointment]);

    const isPaid = appointment?.status === "PAID" || appointment?.extendedProps?.status === "PAID";
    const service = appointment?.service || appointment?.extendedProps?.service;
    const customer = appointment?.customer || appointment?.extendedProps?.customer;
    const basePrice = service?.price ?? 0;

    const displayPrice = isPaid
        ? (appointment?.finalPrice || appointment?.extendedProps?.finalPrice || basePrice)
        : basePrice + extras.reduce((sum, item) => sum + item.price, 0);

    const handleConfirm = async () => {
        setLoading(true);
        try {
            const res = await fetch(`/api/appointments/${appointment.id}/checkout`, {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ totalPrice: displayPrice, extras, note, paymentMethod }),
            });
            if (res.ok) { toast.success("Enregistré !"); onRefresh(); onClose(); }
        } catch (error) { toast.error("Erreur"); } finally { setLoading(false); }
    };

    return (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm flex items-center justify-center z-[100] p-4 text-gray-900">
            <div className="bg-white rounded-3xl w-full max-w-lg shadow-2xl overflow-hidden flex flex-col max-h-[90vh]">

                {/* Header */}
                <div className={`p-6 border-b flex justify-between items-center ${isPaid ? 'bg-green-50' : 'bg-gray-50'}`}>
                    <div className="flex items-center gap-3">
                        {isPaid && <CheckCircle2 className="text-green-600" size={28} />}
                        <div>
                            <h2 className="text-xl font-bold">{isPaid ? "Détails du règlement" : "Encaisser le RDV"}</h2>
                            <p className="text-sm text-gray-500">{customer?.name} — {service?.name}</p>
                        </div>
                    </div>
                    <button onClick={onClose} className="p-2 hover:bg-gray-200 rounded-full"><X size={20}/></button>
                </div>

                <div className="p-6 space-y-6 overflow-y-auto">
                    {/* Section Paiement */}
                    <div className="space-y-3">
                        <h3 className="text-[10px] font-black text-gray-400 uppercase tracking-widest text-center mb-4">Mode de règlement</h3>
                        <div className="grid grid-cols-3 gap-2">
                            <PaymentMethodBtn id="CB" label="Carte" icon={CreditCard} active={paymentMethod === "CB"} disabled={isPaid} onClick={setPaymentMethod} />
                            <PaymentMethodBtn id="CASH" label="Espèces" icon={Banknote} active={paymentMethod === "CASH"} disabled={isPaid} onClick={setPaymentMethod} />
                            <PaymentMethodBtn id="CHECK" label="Chèque" icon={Landmark} active={paymentMethod === "CHECK"} disabled={isPaid} onClick={setPaymentMethod} />
                        </div>
                    </div>

                    {/* Section Note */}
                    <div className="space-y-3 pt-4 border-t border-gray-50">
                        <label className="flex items-center gap-2 text-[10px] font-black text-gray-400 uppercase tracking-widest">
                            <StickyNote size={14} /> Note de séance
                        </label>
                        <textarea
                            value={note}
                            onChange={(e) => setNote(e.target.value)}
                            className="w-full p-4 bg-gray-50 border border-gray-100 rounded-2xl text-sm min-h-[100px] outline-none italic resize-none"
                            placeholder="Observations..."
                        />
                    </div>

                    {/* Section Extras */}
                    <div className="space-y-3 pt-4 border-t border-gray-50">
                        <div className="flex justify-between items-center">
                            <h3 className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Suppléments</h3>
                            {!isPaid && (
                                <button onClick={() => setExtras([...extras, { label: "", price: 0 }])} className="text-[10px] bg-gray-900 text-white px-3 py-1 rounded-full">+ AJOUTER</button>
                            )}
                        </div>
                        {extras.length === 0 && <p className="text-xs text-gray-400 italic">Aucun supplément.</p>}
                        {extras.map((extra, index) => (
                            <ExtraRow
                                key={index}
                                extra={extra}
                                index={index}
                                isPaid={isPaid}
                                onRemove={(i: number) => setExtras(extras.filter((_, idx) => idx !== i))}
                                onUpdate={(i: number, f: keyof Extra, v: string | number) => {
                                    const next = [...extras]; next[i] = { ...next[i], [f]: v }; setExtras(next);
                                }}
                            />
                        ))}
                    </div>
                </div>

                {/* Footer */}
                <div className={`p-6 border-t space-y-4 ${isPaid ? 'bg-green-50/50' : 'bg-gray-50'}`}>
                    <div className="flex justify-between items-end px-2">
                        <span className="text-gray-400 font-bold text-xs uppercase tracking-widest">Total</span>
                        <span className={`text-4xl font-black ${isPaid ? 'text-green-700' : 'text-gray-900'}`}>{displayPrice} €</span>
                    </div>
                    <button
                        onClick={handleConfirm}
                        disabled={loading}
                        className={`w-full py-4 rounded-2xl font-bold text-lg flex items-center justify-center gap-3 transition-all ${isPaid ? 'bg-gray-900' : 'bg-indigo-600'} text-white disabled:opacity-50`}
                    >
                        {loading ? "..." : (isPaid ? <><Save size={20} /> Mettre à jour</> : "Confirmer")}
                    </button>
                </div>
            </div>
        </div>
    );
}

"use client";

import { useState, useEffect } from "react";
import { Plus, Trash2, CreditCard, X, CheckCircle2, StickyNote, Save, Banknote, Landmark } from "lucide-react";
import { toast } from "sonner";
import type { CheckoutAppointment, Extra, AppointmentSummary } from "@/types/models";

// --- SOUS-COMPOSANTS DE STRUCTURE ---

interface PaymentMethodBtnProps {
    id: string
    label: string
    icon: React.ComponentType<{ size?: number }>
    active: boolean
    disabled: boolean
    onClick: (id: string) => void
}

const PaymentMethodBtn = ({ id, label, icon: Icon, active, disabled, onClick }: PaymentMethodBtnProps) => (
    <button
        disabled={disabled}
        onClick={() => onClick(id)}
        className={`flex flex-col items-center gap-2 p-3 rounded-2xl border transition-all ${
            active ? 'bg-indigo-600 border-indigo-600 text-white shadow-lg shadow-indigo-100' : 'bg-white border-gray-100 text-gray-400 hover:border-indigo-200'
        } ${disabled && !active ? 'opacity-20' : ''}`}
    >
        <Icon size={20} />
        <span className="text-[10px] font-bold uppercase">{label}</span>
    </button>
);

interface ExtraRowProps {
    extra: Extra
    index: number
    isPaid: boolean
    onUpdate: (index: number, field: keyof Extra, value: string | number) => void
    onRemove: (index: number) => void
}

const ExtraRow = ({ extra, index, isPaid, onUpdate, onRemove }: ExtraRowProps) => (
    <div className="flex gap-2 items-center group">
        <input
            type="text"
            disabled={isPaid}
            placeholder="Désignation"
            className="flex-1 p-2.5 bg-gray-50 border-none rounded-xl text-sm focus:ring-1 focus:ring-indigo-500/20 disabled:bg-transparent disabled:font-medium"
            value={extra.label}
            onChange={(e) => onUpdate(index, "label", e.target.value)}
        />
        <div className="relative">
            <input
                type="number"
                disabled={isPaid}
                className="w-20 p-2.5 bg-gray-50 border-none rounded-xl text-sm text-right pr-6 focus:ring-1 focus:ring-indigo-500/20 disabled:bg-transparent disabled:font-bold"
                value={extra.price || ""}
                onChange={(e) => onUpdate(index, "price", Number(e.target.value))}
            />
            <span className="absolute right-2 top-1/2 -translate-y-1/2 text-[10px] text-gray-400">€</span>
        </div>
        {!isPaid && (
            <button onClick={() => onRemove(index)} className="p-2 text-red-300 hover:text-red-500 rounded-xl transition-all">
                <Trash2 size={16} />
            </button>
        )}
    </div>
);

// --- COMPOSANT PRINCIPAL ---

interface CheckoutModalProps {
    appointment: (CheckoutAppointment | AppointmentSummary) | null
    onClose: () => void
    onRefresh: () => void
}

export default function CheckoutModal({ appointment, onClose, onRefresh }: CheckoutModalProps) {
    const [extras, setExtras] = useState<Extra[]>([]);
    const [note, setNote] = useState("");
    const [paymentMethod, setPaymentMethod] = useState("CB");
    const [loading, setLoading] = useState(false);

    useEffect(() => {
        if (!appointment) return

        // Narrowing: appointment may be CheckoutAppointment or AppointmentSummary
        // RAISON: extendedProps est typé Record<string,unknown> dans AppointmentSummary; cast local nécessaire pour accéder aux sous-champs
        let rawExtras: string | Extra[] | undefined
        if ('extras' in appointment) {
          // RAISON: extendedProps.extras est unknown — cast local après narrowing 'extras' in appointment
          rawExtras = appointment.extras ?? (appointment.extendedProps?.extras as string | Extra[] | undefined)
        } else {
          // RAISON: extendedProps est Record<string,unknown> dans AppointmentSummary
          rawExtras = appointment.extendedProps ? (appointment.extendedProps['extras'] as string | Extra[] | undefined) : undefined
        }
        setExtras(typeof rawExtras === 'string' ? JSON.parse(rawExtras || "[]") : (rawExtras || []))

        const noteVal = ('note' in appointment ? appointment.note : undefined) ?? ('Note' in appointment ? (appointment as CheckoutAppointment).Note : undefined) ?? appointment.extendedProps?.note ?? ''
        setNote(noteVal as string)

        // RAISON: paymentMethod n'est pas dans AppointmentSummary — narrowing via 'paymentMethod' in
        const pm = ('paymentMethod' in appointment ? (appointment as CheckoutAppointment).paymentMethod : undefined) ?? appointment.extendedProps?.paymentMethod ?? 'CB'
        setPaymentMethod(pm as string)
    }, [appointment]);

    const isPaid = appointment?.status === "PAID" || appointment?.extendedProps?.status === "PAID";
    // RAISON: service/customer peuvent venir de extendedProps (Record<string,unknown>) — cast local après vérification runtime
    const service = appointment?.service || (appointment?.extendedProps?.service as { name?: string; price?: number } | undefined);
    const customer = appointment?.customer || (appointment?.extendedProps?.customer as { name?: string } | undefined);
    const basePrice = service?.price ?? 0;

    // RAISON: extendedProps.finalPrice est unknown — cast number nécessaire pour le calcul
    const extendedFinalPrice = appointment?.extendedProps?.finalPrice as number | undefined
    const displayPrice = isPaid
        ? (appointment?.finalPrice || extendedFinalPrice || basePrice)
        : basePrice + extras.reduce((sum, item) => sum + item.price, 0);

    const handleConfirm = async () => {
        setLoading(true);
        try {
            if (!appointment) return
            const res = await fetch(`/api/appointments/${appointment.id}/checkout`, {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ totalPrice: displayPrice, extras, note, paymentMethod }),
            });
            if (res.ok) { toast.success("Enregistré !"); onRefresh(); onClose(); }
        } catch (error) { toast.error("Erreur"); } finally { setLoading(false); }
    };

    return (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm flex items-center justify-center z-[100] p-4 text-gray-900">
            <div className="bg-white rounded-3xl w-full max-w-lg shadow-2xl overflow-hidden flex flex-col max-h-[90vh]">

                {/* Header */}
                <div className={`p-6 border-b flex justify-between items-center ${isPaid ? 'bg-green-50' : 'bg-gray-50'}`}>
                    <div className="flex items-center gap-3">
                        {isPaid && <CheckCircle2 className="text-green-600" size={28} />}
                        <div>
                            <h2 className="text-xl font-bold">{isPaid ? "Détails du règlement" : "Encaisser le RDV"}</h2>
                            <p className="text-sm text-gray-500">{customer?.name} — {service?.name}</p>
                        </div>
                    </div>
                    <button onClick={onClose} className="p-2 hover:bg-gray-200 rounded-full"><X size={20}/></button>
                </div>

                <div className="p-6 space-y-6 overflow-y-auto">
                    {/* Section Paiement */}
                    <div className="space-y-3">
                        <h3 className="text-[10px] font-black text-gray-400 uppercase tracking-widest text-center mb-4">Mode de règlement</h3>
                        <div className="grid grid-cols-3 gap-2">
                            <PaymentMethodBtn id="CB" label="Carte" icon={CreditCard} active={paymentMethod === "CB"} disabled={isPaid} onClick={setPaymentMethod} />
                            <PaymentMethodBtn id="CASH" label="Espèces" icon={Banknote} active={paymentMethod === "CASH"} disabled={isPaid} onClick={setPaymentMethod} />
                            <PaymentMethodBtn id="CHECK" label="Chèque" icon={Landmark} active={paymentMethod === "CHECK"} disabled={isPaid} onClick={setPaymentMethod} />
                        </div>
                    </div>

                    {/* Section Note */}
                    <div className="space-y-3 pt-4 border-t border-gray-50">
                        <label className="flex items-center gap-2 text-[10px] font-black text-gray-400 uppercase tracking-widest">
                            <StickyNote size={14} /> Note de séance
                        </label>
                        <textarea
                            value={note}
                            onChange={(e) => setNote(e.target.value)}
                            className="w-full p-4 bg-gray-50 border border-gray-100 rounded-2xl text-sm min-h-[100px] outline-none italic resize-none"
                            placeholder="Observations..."
                        />
                    </div>

                    {/* Section Extras */}
                    <div className="space-y-3 pt-4 border-t border-gray-50">
                        <div className="flex justify-between items-center">
                            <h3 className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Suppléments</h3>
                            {!isPaid && (
                                <button onClick={() => setExtras([...extras, { label: "", price: 0 }])} className="text-[10px] bg-gray-900 text-white px-3 py-1 rounded-full">+ AJOUTER</button>
                            )}
                        </div>
                        {extras.length === 0 && <p className="text-xs text-gray-400 italic">Aucun supplément.</p>}
                        {extras.map((extra, index) => (
                            <ExtraRow
                                key={index}
                                extra={extra}
                                index={index}
                                isPaid={isPaid}
                                onRemove={(i: number) => setExtras(extras.filter((_, idx) => idx !== i))}
                                onUpdate={(i: number, f: keyof Extra, v: string | number) => {
                                    const next = [...extras]; next[i] = { ...next[i], [f]: v }; setExtras(next);
                                }}
                            />
                        ))}
                    </div>
                </div>

                {/* Footer */}
                <div className={`p-6 border-t space-y-4 ${isPaid ? 'bg-green-50/50' : 'bg-gray-50'}`}>
                    <div className="flex justify-between items-end px-2">
                        <span className="text-gray-400 font-bold text-xs uppercase tracking-widest">Total</span>
                        <span className={`text-4xl font-black ${isPaid ? 'text-green-700' : 'text-gray-900'}`}>{displayPrice} €</span>
                    </div>
                    <button
                        onClick={handleConfirm}
                        disabled={loading}
                        className={`w-full py-4 rounded-2xl font-bold text-lg flex items-center justify-center gap-3 transition-all ${isPaid ? 'bg-gray-900' : 'bg-indigo-600'} text-white disabled:opacity-50`}
                    >
                        {loading ? "..." : (isPaid ? <><Save size={20} /> Mettre à jour</> : "Confirmer")}
                    </button>
                </div>
            </div>
        </div>
    );
}

"use client";

import {
    ResponsiveContainer,
    AreaChart,
    Area,
    XAxis,
    YAxis,
    Tooltip,
    CartesianGrid,
    Line,
    Legend,
    ReferenceLine,
} from "recharts";

interface ChartData {
    date: string;
    realized: number;
    planned: number;
    count: number;
    target?: number;
}

export default function DashboardCharts({ data }: { data: ChartData[] }) {
    // On formate la date pour l'affichage (ex: 2024-10-12 -> 12/10)
    const formattedData = data.map((d) => ({
        ...d,
        displayDate: d.date.split("-").reverse().slice(0, 2).join("/"),
    }));

    return (
        <div className="h-[400px] w-full bg-white p-6 rounded-2xl border border-gray-100 shadow-sm">
        <div className="mb-6">
        <h3 className="text-lg font-semibold text-gray-900">Activité commerciale</h3>
    <p className="text-sm text-gray-500">Chiffre d&apos;affaires journalier (€)</p>
    </div>

    <ResponsiveContainer width="100%" height={350}>
    <AreaChart data={formattedData} margin={{ top: 10, right: 10, left: -20, bottom: 0 }}>
    <defs>
        <linearGradient id="colorRevenue" x1="0" y1="0" x2="0" y2="1">
    <stop offset="5%" stopColor="#6366f1" stopOpacity={0.15} />
    <stop offset="95%" stopColor="#6366f1" stopOpacity={0} />
    </linearGradient>
    </defs>

    <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f3f4f6" />

    {/* Reference line showing daily target (if present on first data point) */}
    {formattedData && formattedData.length > 0 && (
      <ReferenceLine
        y={formattedData[0]?.target ?? 0}
        stroke="#ef4444"
        label={{ position: 'right', value: 'Objectif', fill: '#ef4444' }}
      />
    )}

    <XAxis
        dataKey="displayDate"
    fontSize={12}
    tickLine={false}
    axisLine={false}
    tick={{ fill: '#9ca3af' }}
    minTickGap={30}
    />

    <YAxis
    fontSize={12}
    tickLine={false}
    axisLine={false}
    tick={{ fill: '#9ca3af' }}
    tickFormatter={(value) => `${value}€`}
    />

    <Tooltip
    contentStyle={{
        backgroundColor: '#fff',
            borderRadius: '12px',
            border: 'none',
            boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)'
    }}
    itemStyle={{ color: '#6366f1', fontWeight: 'bold' }}
    formatter={(value: number | string | undefined) => [`${Number(value ?? 0)} €`, "Revenu"]}
    labelStyle={{ color: '#6b7280', marginBottom: '4px' }}
    />

        <Legend
            iconType="circle"
            wrapperStyle={{ paddingTop: "20px" }}
            formatter={(value) => (
                <span className="text-sm text-gray-600 ml-2">
                {String(value) === "realized" ? "CA Réalisé" : "CA Prévu"}
              </span>
            )}
        />

        {/* Ligne 2 : CA Prévu (Ligne Pointillée) - On la met en premier pour qu'elle soit derrière */}
        <Line
            type="monotone"
            dataKey="planned"
            name="planned"
            stroke="#94a3b8" // Gris bleu discret
            strokeWidth={2}
            strokeDasharray="5 5" // Ligne en pointillés
            dot={false}
            activeDot={{ r: 6, stroke: "#94a3b8", strokeWidth: 2, fill: "#fff" }}
        />

    <Area
    type="monotone"
    dataKey="realized"
    stroke="#6366f1"
    strokeWidth={3}
    fillOpacity={1}
    fill="url(#colorRevenue)"
    animationDuration={1500}
    />
    </AreaChart>
    </ResponsiveContainer>
    </div>
);
}

