export interface DashboardData {
  summary: DashboardSummary
  timeseries: DashboardTimeseries[]
}

/** Shape d'un rendez-vous reçue par CheckoutModal (API appointments) */
export interface CheckoutAppointment {
  id: string
  startTime?: string | Date
  start?: string
  end?: string
  title?: string
  status?: string
  extras?: string | Extra[]
  note?: string
  Note?: string
  paymentMethod?: string
  finalPrice?: number
  service?: { name?: string; price?: number } | null
  customer?: { name?: string } | null
  extendedProps?: {
    status?: string
    extras?: string | Extra[]
    note?: string
    paymentMethod?: string
    finalPrice?: number
    service?: { name?: string; price?: number } | null
    customer?: { name?: string } | null
  }
}

export interface Extra {
  label: string
  price: number
}

// Summary shape used for lists and lightweight UI components
export interface AppointmentSummary {
  id: string
  // Some UI components expect a `startTime` field (checkout shape). Make it optional
  // to simplify handling when components receive either CheckoutAppointment or AppointmentSummary.
  startTime?: string | Date
  start: string
  end?: string
  status?: string
  finalPrice?: number | null
  service?: { id?: string; name?: string; price?: number } | null
  customer?: { id?: string; name?: string } | null
  extendedProps?: Record<string, unknown>
}

export interface Client {
  id: string
  firstName: string
  lastName: string
  phone?: string
  Note?: string
  appointments?: CheckoutAppointment[]
}
export interface Organization {
  id: string
  name: string
}

export interface Service {
  id: string
  name: string
  durationMinutes: number
  price: number
  color?: string | null
  organizationId?: string | null
}

export interface Customer {
  id: string
  firstName: string
  lastName: string
  phone: string
  email?: string | null
  organizationId?: string | null
}

export interface Staff {
  id: string
  firstName: string
  lastName: string
  organizationId?: string | null
}

export interface Session {
  userId: string
  email?: string | null
  name?: string | null
  role?: string | null
  organizationId?: string | null
  [key: string]: unknown
}

// Minimal token shape returned by Auth.js / JWT used in the proxy.
// Replace earlier usages of Record<string, unknown> when narrowing token values.
export interface AuthToken {
  sub: string
  email?: string
  organizationId?: string
  // allow additional claims without widening commonly used fields
  [key: string]: unknown
}

export interface Appointment {
  id: string
  title?: string | null
  startTime: Date
  endTime: Date
  duration: number
  serviceId: string
  customerId: string
  staffId: string
  organizationId: string
  createdAt: Date
  updatedAt: Date
}

export type InitialAppointmentData = Partial<{
  id: string
  title: string
  start: string
  end: string
  serviceId: string
  customerId: string
  staffId: string
  duration: number
  extendedProps: Record<string, unknown>
  resourceId: string
}>

// Minimal session / auth types used across the app
// Note: Session type is declared above and reused by imports; avoid duplicating it here.

import { describe, it, expect, vi, beforeEach } from 'vitest'

// mock prisma used by the service
const mockFindMany = vi.fn()
const mockCustomerCount = vi.fn()
const mockStaffCount = vi.fn()

vi.mock('../src/lib/prisma', () => ({
  prisma: {
    appointment: { findMany: (opts: unknown) => mockFindMany(opts) },
    customer: { count: (opts: unknown) => mockCustomerCount(opts) },
    staff: { count: (opts: unknown) => mockStaffCount(opts) },
  },
}))

import { getOrgDashboard } from '../src/services/analytics.service'

beforeEach(() => {
  vi.resetAllMocks()
})

describe('analytics.getOrgDashboard', () => {
  it('computes summary and timeseries for a 2-day range', async () => {
    const appointments = [
      { startTime: new Date('2026-03-30T10:00:00Z'), service: { price: 50 } },
      { startTime: new Date('2026-03-31T12:00:00Z'), service: { price: 100 } },
      { startTime: new Date('2026-03-31T15:00:00Z'), service: { price: null } },
    ]

    mockFindMany.mockResolvedValue(appointments)
    mockCustomerCount.mockResolvedValue(5)
    mockStaffCount.mockResolvedValue(2)

    const start = new Date('2026-03-30T00:00:00Z')
    const end = new Date('2026-03-31T23:59:59Z')

    const res = await getOrgDashboard('org-1', start, end)

    // Summary
    expect(res.summary.totalRevenue).toBe(150)
    expect(res.summary.appointmentCount).toBe(3)
    expect(res.summary.newCustomerCount).toBe(5)

    // Time series should contain two days (30 and 31 march)
    expect(res.timeSeries).toHaveLength(2)
    const [d30, d31] = res.timeSeries
    expect(d30.count).toBe(1)
    expect(d30.revenue).toBe(50)
    expect(d31.count).toBe(2)
    expect(d31.revenue).toBe(100)
  })
})

import { describe, it, expect, vi, beforeEach } from 'vitest'

// mock prisma used by the service
const mockFindMany = vi.fn()
const mockCustomerCount = vi.fn()
const mockStaffCount = vi.fn()
const mockOrgFindUnique = vi.fn()

vi.mock('../src/lib/prisma', () => ({
  prisma: {
    appointment: { findMany: (opts: unknown) => mockFindMany(opts) },
    customer: { count: (opts: unknown) => mockCustomerCount(opts) },
    staff: { count: (opts: unknown) => mockStaffCount(opts) },
    organization: { findUnique: (opts: unknown) => mockOrgFindUnique(opts) },
  },
}))

import { getDashboardForOrg } from '../src/services/dashboard.service'

beforeEach(() => {
  vi.resetAllMocks()
  mockOrgFindUnique.mockResolvedValue(null)
})

describe('analytics.getOrgDashboard', () => {
  it('computes summary and timeseries for a 2-day range', async () => {
    const appointments = [
      { startTime: new Date('2026-03-30T10:00:00Z'), service: { price: 50 }, status: 'CONFIRMED', finalPrice: null },
      { startTime: new Date('2026-03-31T12:00:00Z'), service: { price: 100 }, status: 'CONFIRMED', finalPrice: null },
      { startTime: new Date('2026-03-31T15:00:00Z'), service: { price: null }, status: 'CONFIRMED', finalPrice: null },
    ]

    mockFindMany.mockResolvedValue(appointments)
    mockCustomerCount.mockResolvedValue(5)
    mockStaffCount.mockResolvedValue(2)

    const start = new Date('2026-03-30T00:00:00Z')
    const end = new Date('2026-03-31T23:59:59Z')

    const res = await getDashboardForOrg('org-1', { start, end })

    // Summary: totalProjected = somme des prix de service (non PAID → service.price)
    expect(res.summary.totalProjected).toBe(150)
    expect(res.summary.appointmentCount).toBe(3)
    expect(res.summary.newCustomerCount).toBe(5)

    // Time series should contain two days (30 and 31 march)
    expect(res.timeseries).toHaveLength(2)
    const [d30, d31] = res.timeseries
    expect(d30.count).toBe(1)
    expect(d30.planned).toBe(50)
    expect(d31.count).toBe(2)
    expect(d31.planned).toBe(100)
  })
})

import { describe, it, expect, vi, beforeEach } from 'vitest'
import { NextResponse } from 'next/server'

// Mock the adapter functions so we control token/session resolution
const mockGetTokenFromRequest = vi.fn()
const mockGetTypedServerSession = vi.fn()

vi.mock('../src/lib/nextAuthAdapter', () => ({
  getTokenFromRequest: (req: unknown) => mockGetTokenFromRequest(req),
  getTypedServerSession: () => mockGetTypedServerSession(),
}))

// mock ensureNextAuthSecret used by proxy to be a no-op in tests
vi.mock('../src/lib/checkEnv', () => ({
  ensureNextAuthSecret: () => undefined,
}))

import { middleware } from '../src/middleware'

beforeEach(() => {
  vi.resetAllMocks()
})

describe('proxy middleware', () => {
  it('allows public paths without auth', async () => {
    const req = { nextUrl: { pathname: '/auth' }, url: 'http://localhost/auth' } as any
    const res = await middleware(req)
    // Should return a NextResponse (pass-through)
    expect(res).toBeDefined()
    // No x-org-id injected for public path
    expect(res.headers?.get && res.headers.get('x-org-id')).toBeNull()
  })

  it('injects x-org-id when token/session has organizationId', async () => {
    mockGetTokenFromRequest.mockResolvedValue({ sub: 'u1', organizationId: 'org-1' })
    mockGetTypedServerSession.mockResolvedValue({ userId: 'u1', organizationId: 'org-1', email: null, name: null, role: null, roles: [] })

    const req = { nextUrl: { pathname: '/dashboard' }, url: 'http://localhost/dashboard' } as any
    const res = await middleware(req)
    expect(res).toBeDefined()
    // x-org-id must be set to the organizationId
    expect(res.headers?.get && res.headers.get('x-org-id')).toBe('org-1')
  })

  it('returns 403 for api routes when organizationId missing', async () => {
    mockGetTokenFromRequest.mockResolvedValue({ sub: 'u2' })
    mockGetTypedServerSession.mockResolvedValue(null)

    const req = { nextUrl: { pathname: '/api/secure' }, url: 'http://localhost/api/secure' } as any
    const res = await middleware(req)
    // API forbidden response should have status 403
    expect((res as any).status).toBe(403)
  })
})

import { describe, it, expect, vi, beforeEach } from 'vitest'

// Contrôle la session injectée par auth() — simule le comportement de next-auth v5
let mockSession: unknown = null

vi.mock('../src/auth', () => ({
  // auth(callback) retourne un handler qui injecte req.auth avant d'appeler le callback
  auth: (callback: (req: unknown) => unknown) => async (req: unknown) => {
    return callback({ ...(req as object), auth: mockSession })
  },
}))

import { middleware } from '../src/proxy'

beforeEach(() => {
  mockSession = null
})

describe('proxy middleware', () => {
  it('passe les pages /auth sans vérifier la session', async () => {
    mockSession = null // non authentifié
    const req = {
      nextUrl: new URL('http://localhost/auth/signin'),
      url: 'http://localhost/auth/signin',
    }
    const res = await middleware(req as any)
    // Pas de redirection — path public
    expect(res).toBeUndefined()
  })

  it('laisse passer un utilisateur authentifié', async () => {
    mockSession = { user: { id: 'u1', organizationId: 'org-1' } }
    const req = {
      nextUrl: new URL('http://localhost/dashboard'),
      url: 'http://localhost/dashboard',
    }
    const res = await middleware(req as any)
    // Pas de redirection
    expect(res).toBeUndefined()
  })

  it('redirige vers /auth/signin si non authentifié sur une page protégée', async () => {
    mockSession = null
    const req = {
      nextUrl: new URL('http://localhost/dashboard'),
      url: 'http://localhost/dashboard',
    }
    const res = await middleware(req as any)
    // Redirection vers signin
    expect(res?.status).toBeGreaterThanOrEqual(301)
    expect(res?.status).toBeLessThanOrEqual(308)
    expect(res?.headers?.get('location')).toContain('/auth/signin')
  })
})
